create table dirkspzm32.wdg_cfg (
    sid               varchar2(2 char) default '01' not null enable,
    firma_nr          number(6, 0) default 1 not null enable,
    wdg_cfg_id        number(*, 0) not null enable,
    hostname          varchar2(150 char) not null enable,
    check_type        varchar2(20 char) not null enable,
    warn_max_value    number(*, 12) default 999999999999 not null enable,
    error_min_value   number(*, 12) default 0 not null enable,
    data_interval_sec number(*, 12) default 30 not null enable,
    warn_min_value    number(*, 12) default 0 not null enable,
    hdd_root_path     varchar2(3 char),
    error_max_value   number(*, 5) default 999999999999 not null enable,
    logger_delta_sec  number(*, 12) default 60 not null enable,
    app_exename       varchar2(150 char) not null enable,
    active            varchar2(1 char) default 'F' not null enable
);

alter table dirkspzm32.wdg_cfg
    add constraint pk_wdg_cfg
        primary key ( sid,
                      firma_nr,
                      wdg_cfg_id )
            using index enable;


